function test_implode_params() {
    $exchange = new \ccxt\async\Exchange(array(
        'id' => 'sampleexchange',
    ));
    $path = 'v2/watchlists/{timeframe_id}/{symbol_id}';
    $params = array(
        'timeframe_id' => '1m',
        'symbol_id' => 'BTC/USDT',
        'extra_param' => 'should_be_ignored',
    );
    $expected = 'v2/watchlists/1m/BTC/USDT';
    $result = $exchange->implode_params($path, $params);
    assert($result === $expected, 'implodeParams did not produce the expected result: ' . $result . ' != ' . $expected);
}
